import { ipcMain } from 'electron';
import { z } from 'zod';
import { randomUUID } from 'crypto';
import {
  IPC_CHANNELS,
  FavoritePathServerSchema,
  CreateFavoritePathSchema,
  UpdateFavoritePathSchema,
  FavoritePathIdSchema,
} from './types';
import { queries } from '../db';

export function registerFavoritePathsHandlers() {
  // List favorite paths for a server
  ipcMain.handle(IPC_CHANNELS.FAVORITE_PATHS_LIST, async (_event, input) => {
    try {
      const { serverId } = FavoritePathServerSchema.parse(input);
      const paths = queries.getFavoritePathsByServer(serverId);
      return { success: true, data: paths };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to list favorite paths',
      };
    }
  });

  // Create a favorite path
  ipcMain.handle(IPC_CHANNELS.FAVORITE_PATHS_CREATE, async (_event, input) => {
    try {
      const { serverId, name, path } = CreateFavoritePathSchema.parse(input);
      const existing = queries.getFavoritePathsByServer(serverId);
      const maxOrder = existing.reduce((max, f) => Math.max(max, f.display_order), 0);

      const id = randomUUID();
      queries.createFavoritePath({
        id,
        server_id: serverId,
        name,
        path,
        display_order: maxOrder + 1,
      });

      const created = queries.getFavoritePathsByServer(serverId).find(f => f.id === id);
      return { success: true, data: created };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to create favorite path',
      };
    }
  });

  // Update a favorite path
  ipcMain.handle(IPC_CHANNELS.FAVORITE_PATHS_UPDATE, async (_event, input) => {
    try {
      const { id, name, path, displayOrder } = UpdateFavoritePathSchema.parse(input);
      const updates: Record<string, any> = {};
      if (name !== undefined) updates.name = name;
      if (path !== undefined) updates.path = path;
      if (displayOrder !== undefined) updates.display_order = displayOrder;

      queries.updateFavoritePath(id, updates);
      return { success: true };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to update favorite path',
      };
    }
  });

  // Delete a favorite path
  ipcMain.handle(IPC_CHANNELS.FAVORITE_PATHS_DELETE, async (_event, input) => {
    try {
      const { id } = FavoritePathIdSchema.parse(input);
      queries.deleteFavoritePath(id);
      return { success: true };
    } catch (error) {
      if (error instanceof z.ZodError) {
        return { success: false, error: error.issues[0]?.message || 'Validation failed' };
      }
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Failed to delete favorite path',
      };
    }
  });
}
